from microbit import *
import radio


radio.config(group=1)
radio.on()
max = 0

while True:
    if button_a.was_pressed():
        display.scroll(max)
    sound_level = radio.receive()
    if sound_level:
        if int(sound_level) > max:
            max = int(sound_level)
